'use strict';
// Wraps the native mobile_bridge linked binding with a channel-based API.
const native = process._linkedBinding('mobile_bridge');

const listeners = Object.create(null); // channel → [fn, ...]

native.setReceiver((channel, message) => {
  const fns = listeners[channel];
  if (fns) fns.forEach(fn => fn(message));
});

module.exports = {
  send(channel, message) {
    native.send(channel, message);
  },
  on(channel, fn) {
    if (!listeners[channel]) listeners[channel] = [];
    listeners[channel].push(fn);
  },
  off(channel, fn) {
    if (!listeners[channel]) return;
    if (fn) {
      listeners[channel] = listeners[channel].filter(f => f !== fn);
    } else {
      delete listeners[channel];
    }
  },
};
